function BillOfMaterials(t,e){var a=this,n=$("#"+t);this.tabID=t;n.find("[name=hidId]").val();this.tablekey=e.TABLEKEY;var l=new Array;l.push({object:"hidItemKeyDetail[]",value:"pkey"});var m=l;this.updateDetail=function(t,e,a){var n=$(t).closest(".transaction-detail-row");for(i=0;i<e.length;i++)n.find("[name='"+e[i].object+"']").first().val(a.item[e[i].value]).change().blur();if(""!=a.item.value){n.find('[name="itemNameDetail[]"]').first().val(a.item.value),n.find(".baseitemunit").html(a.item.baseunitname)}},this.rebindEl=function(){bindAutoCompleteForTransactionDetail("itemNameDetail[]",m,"ajax-item.php?action=searchData&itemtype=1&limit=25",a.updateDetail)},this.loadOnReady=function(){a.rebindEl()}}